solution_code:
#include <iostream>

int lvalue_count = 0;
int rvalue_count = 0;

void record(int& x) {
    (void)x;
    ++lvalue_count;
}

void record(int&& x) {
    (void)x;
    ++rvalue_count;
}

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        int val;
        std::cin >> val;
        if (val > 0) {
            record(val);
        } else {
            record(val + 0);
        }
    }
    std::cout << "Lvalue calls: " << lvalue_count << "\n";
    std::cout << "Rvalue calls: " << rvalue_count << "\n";
    return 0;
}

