#include <iostream>

int total = 0;

void accumulate(int&& val) {
    total += val;
}

int main() {
    int n;
    std::cin >> n;
    for (int i = 0; i < n; ++i) {
        int x;
        std::cin >> x;
        accumulate(x + 0);
    }
    std::cout << "Total: " << total << "\n";
    return 0;
}
